function RapidCounter() {
  const [count, setCount] = useState(0);

  async function handleClick() {
    setCount(count + 1);
    await fetch('/api/track-click', { method: 'POST' });
    setCount(count + 1);
  }

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={handleClick}>Click me</button>
    </div>
  );
}
